import { Component, OnInit, OnDestroy } from '@angular/core';
import { Router } from '@angular/router';
import { HttpClient } from '@angular/common/http';
import { AuthService } from '../../services/auth.service';

@Component({
  selector: 'app-interviewer-dashboard',
  template: `
  <div style="padding:40px;background:white;min-height:100vh">
    <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:30px">
      <h2 style="margin:0">Welcome {{auth.user?.interviewerName}}</h2>
      <button (click)="logout()" style="background:#000;color:#fff;padding:4px 12px;border:none;border-radius:6px;cursor:pointer">Logout</button>
    </div>

    <p *ngIf="applications.length===0" style="opacity:0.6">No interview requests</p>

    <div *ngFor="let app of applications" style="background:#f5f5f5;padding:20px;border-radius:10px;border:1px solid white;margin-bottom:20px">
      <div style="display:flex;justify-content:space-between;align-items:center">
        <h3 style="margin:0">{{app.candidateName}}</h3>
        <span style="font-size:12px;background:#f5f5f5;padding:3px 8px;border-radius:6px">{{ getLevel(app) }}</span>
      </div>

      <div style="display:flex;gap:20px;margin-top:10px;font-size:14px">
        <span><b>Date:</b> {{ formatDate(getDate(app)) }}</span>
        <span><b>Time:</b> {{ formatTime(getTime(app)) }}</span>
        <span><b>Mode:</b> {{ getMode(app) }}</span>
      </div>

      <div *ngIf="getInterviewerStatus(app) === 'REQUESTED'">
        <p style="font-size:13px;opacity:0.7">HR assigned this interview</p>
        <div style="display:flex;gap:10px;margin-top:10px">
          <button (click)="respondToRequest(app.id,'ACCEPTED')" style="background:#000;color:#fff;border:none;padding:6px 12px;border-radius:6px;cursor:pointer">Accept</button>
          <button (click)="respondToRequest(app.id,'REJECTED')" style="background:#eaeaea;border:none;padding:6px 12px;border-radius:6px;cursor:pointer">Reject</button>
        </div>
      </div>

      <div *ngIf="getInterviewerStatus(app) === 'ACCEPTED' && app.interviewStatus.includes('SCHEDULED')">
        <p style="font-size:13px;opacity:0.7">Interview accepted</p>
        <div style="display:flex;gap:10px;margin-top:10px">
          <button (click)="updateResult(app.id, getLevel(app) === 'L1' ? 'L1_PASSED' : 'L2_PASSED')" [disabled]="isResultDone(app)" style="background:#000;color:#fff;border:none;padding:6px 12px;border-radius:6px;cursor:pointer">Mark as Passed</button>
          <button (click)="updateResult(app.id, getLevel(app) === 'L1' ? 'L1_FAILED' : 'L2_FAILED')" [disabled]="isResultDone(app)" style="background:#eaeaea;border:none;padding:6px 12px;border-radius:6px;cursor:pointer">Mark as Failed</button>
        </div>
      </div>

      <p *ngIf="getLevel(app) === 'L1' && app.l1Result === 'PASSED'" style="color:black;font-weight:bold;font-size:13px">Candidate cleared this round</p>
      <p *ngIf="getLevel(app) === 'L2' && app.l2Result === 'PASSED'" style="color:black;font-weight:bold;font-size:13px">Candidate cleared this round</p>
      <p *ngIf="getLevel(app) === 'L1' && app.l1Result === 'FAILED'" style="color:red;font-weight:500;font-size:13px">Candidate failed this round</p>
      <p *ngIf="getLevel(app) === 'L2' && app.l2Result === 'FAILED'" style="color:red;font-weight:500;font-size:13px">Candidate failed this round</p>
    </div>
  </div>
  `
})
export class InterviewerDashboardComponent implements OnInit, OnDestroy {
  applications: any[] = [];
  private intervalId: any;

  constructor(public auth: AuthService, private http: HttpClient, private router: Router) {}

  ngOnInit() {
    if (!this.auth.user || this.auth.user.role !== 'INTERVIEWER') { this.router.navigate(['/']); return; }
    this.fetchApplications();
    this.intervalId = setInterval(() => this.fetchApplications(), 5000);
  }

  ngOnDestroy() { clearInterval(this.intervalId); }

  logout() { this.auth.logout(); this.router.navigate(['/']); }

  async fetchApplications() { try { const id = this.auth.user?.interviewerId; this.applications = await this.http.get<any[]>(`http://localhost:8080/api/applications/interviewer/${id}`).toPromise(); } catch (err) { console.error(err); } }

  async respondToRequest(applicationId: any, status: string) { await this.http.post('http://localhost:8080/api/applications/interviewer-response', null, { params: { applicationId, status } as any }).toPromise(); this.fetchApplications(); }

  async updateResult(applicationId: any, result: string) { await this.http.post('http://localhost:8080/api/applications/update-interview-result', null, { params: { applicationId, result } as any }).toPromise(); this.fetchApplications(); }

  formatDate(dateString: any) { if (!dateString) return ''; return new Date(dateString).toLocaleDateString('en-GB', { day: '2-digit', month: 'short', year: 'numeric' }); }

  formatTime(time: string) { if (!time) return ''; const [h, m] = time.split(':'); const d = new Date(); d.setHours(Number(h), Number(m)); return d.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }); }

  getLevel(app: any) { const id = this.auth.user?.interviewerId; return Number(id) === app.l1InterviewerId ? 'L1' : 'L2'; }
  getInterviewerStatus(app: any) { const id = this.auth.user?.interviewerId; return Number(id) === app.l1InterviewerId ? app.l1InterviewerStatus : app.l2InterviewerStatus; }
  getDate(app: any) { const id = this.auth.user?.interviewerId; return Number(id) === app.l1InterviewerId ? app.l1Date : app.l2Date; }
  getTime(app: any) { const id = this.auth.user?.interviewerId; return Number(id) === app.l1InterviewerId ? app.l1Time : app.l2Time; }
  getMode(app: any) { const id = this.auth.user?.interviewerId; return Number(id) === app.l1InterviewerId ? app.l1Mode : app.l2Mode; }

  isResultDone(app: any) { const level = this.getLevel(app); return level === 'L1' ? (app.l1Result === 'PASSED' || app.l1Result === 'FAILED') : (app.l2Result === 'PASSED' || app.l2Result === 'FAILED'); }
}
